#include <iostream>
#include <cmath>
#include <algorithm>
#include <iomanip>

using namespace std;

// Global variables for geometry parameters
double A, R1, R2, R3;
double SQRT3;

// Function to calculate the length of the intersection segment at a given height y
double f(double y) {
    // 1. Triangle bounds at height y
    double L = -(A - y / SQRT3);
    double R = A - y / SQRT3;

    // 2. Circle 1 (centered at 0, 0)
    if (abs(y) > R1) return 0.0;
    double dx1 = sqrt(max(0.0, R1 * R1 - y * y));
    L = max(L, -dx1);
    R = min(R, dx1);

    // 3. Circle 2 (centered at A/2, A*sqrt(3)/2)
    double y2 = A * SQRT3 / 2.0;
    if (abs(y - y2) > R2) return 0.0;
    double dx2 = sqrt(max(0.0, R2 * R2 - (y - y2) * (y - y2)));
    L = max(L, A / 2.0 - dx2);
    R = min(R, A / 2.0 + dx2);

    // 4. Circle 3 (centered at -A/2, A*sqrt(3)/2)
    double y3 = A * SQRT3 / 2.0;
    if (abs(y - y3) > R3) return 0.0;
    double dx3 = sqrt(max(0.0, R3 * R3 - (y - y3) * (y - y3)));
    L = max(L, -A / 2.0 - dx3);
    R = min(R, -A / 2.0 + dx3);

    // If the left bound exceeds the right bound, there is no intersection at this y
    return max(0.0, R - L);
}

void solve() {
    cin >> A >> R1 >> R2 >> R3;
    double H = A * SQRT3;

    // Simpson's rule configuration
    int N = 2000000; // 2 million even intervals gives extreme precision
    double h = H / N;

    double sum = f(0) + f(H);

    // Simpson's 1/3 Rule logic
    for (int i = 1; i < N; i += 2) {
        sum += 4.0 * f(i * h);
    }
    for (int i = 2; i < N; i += 2) {
        sum += 2.0 * f(i * h);
    }

    double area = sum * h / 3.0;

    // The problem requires answer error <= 5 * 10^-2. 
    // Setting precision to 7 easily covers this.
    cout << fixed << setprecision(7) << area << "\n";
}

int main() {
    // Fast I/O
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    SQRT3 = sqrt(3.0);

    int T;
    if (cin >> T) {
        while (T--) {
            solve();
        }
    }
    return 0;
}
